-- Import the user-supplied research peptide review JSON without publishing it.
--
-- The source lacks consent, relationship/incentive disclosure, verification,
-- claim-review, reviewer, and publication records. Every row therefore remains
-- a draft in the private base table and cannot pass published_testimonials.
-- Source content below is copied verbatim; only category and stable internal
-- identifiers are derived.

alter table public.testimonials
  add column if not exists review_title text not null default '',
  add column if not exists product_name text not null default '',
  add column if not exists rating smallint,
  add column if not exists verified_purchase boolean,
  add column if not exists source_review_id text,
  add column if not exists source_user_style text not null default '',
  add column if not exists source_length_label text not null default '',
  add column if not exists import_fingerprint text;

-- Unknown incentive status must remain unknown until an administrator verifies
-- it. Treating missing source data as "no incentive" would weaken the gate.
alter table public.testimonials
  alter column incentive_provided drop default,
  alter column incentive_provided drop not null;

do $$ begin
  alter table public.testimonials
    add constraint testimonials_rating_range
    check (rating is null or rating between 1 and 5);
exception when duplicate_object then null; end $$;

create unique index if not exists testimonials_import_fingerprint_unique
  on public.testimonials (import_fingerprint)
  where import_fingerprint is not null;

insert into public.testimonials (
  id,
  status,
  category,
  quote,
  display_name,
  review_title,
  product_name,
  rating,
  verified_purchase,
  submission_date,
  source_review_id,
  source_user_style,
  source_length_label,
  source_record_reference,
  import_fingerprint,
  sort_order,
  incentive_provided
)
values
  ('ec0e0000-0000-5000-8000-000000000001'::uuid, 'fulfillment'::public.testimonial_category, 'Third order from this vial and the purity has been rock solid every time. Shipping was fast and packaging kept everything cold.', 'Mike T.', 'Consistent quality every time', 'BPC-157', 5, true, '2026-06-02'::date, '1', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=1', 'ec8086ca-e4eb-5881-8402-f16ebd5172d3', 0, null),
  ('ec0e0000-0000-5000-8000-000000000002'::uuid, 'documentation'::public.testimonial_category, 'I ran a third-party HPLC check against the included COA and the purity was within 0.3% of what was listed, which is better than most vendors I''ve dealt with. Pros: batch numbers are traceable, reconstitution was clean with no visible particulate, and the lyophilization looked uniform. Con: the site doesn''t let you filter by batch number when reordering, so I had to email support to confirm I was getting the same lot. Support responded within a day, which softened that complaint. Overall this is now my default vendor for lab comparisons.', 'K.L. (PhD)', 'COA matched independent HPLC results', 'TB-500', 5, true, '2026-05-14'::date, '2', 'technical_expert', 'detailed', 'research_peptide_mock_reviews.json#id=2', 'c5b77f4f-d1a6-5e80-89e4-de4bb69c7d32', 1, null),
  ('ec0e0000-0000-5000-8000-000000000003'::uuid, 'fulfillment'::public.testimonial_category, 'Product itself seems fine and well packaged, just took almost a week longer than the estimate to arrive.', 'Ashley G.', 'Good, shipping took a bit', 'Semaglutide', 4, true, '2026-04-22'::date, '3', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=3', '2a0eab02-9d26-5d41-8cdd-c3667c7f584f', 2, null),
  ('ec0e0000-0000-5000-8000-000000000004'::uuid, 'service'::public.testimonial_category, 'Been ordering for over a year now and never had a bad batch. Easy checkout, discreet packaging.', 'David R.', 'Reliable vendor', 'Ipamorelin', 5, true, '2026-06-19'::date, '4', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=4', 'cfd614b7-b7fe-56e4-83fb-696bf619eff2', 3, null),
  ('ec0e0000-0000-5000-8000-000000000005'::uuid, 'fulfillment'::public.testimonial_category, 'My brother runs a small home lab and is picky about vendors, so I asked him what to get before ordering this for his birthday. He said the vial arrived well sealed with an ice pack and the paperwork was all there. I don''t personally know enough to judge purity, but he was happy and that''s what matters for a gift. Ordering and shipping tracking were both straightforward on my end.', 'Deb (sister-in-law)', 'Bought this for my brother''s lab supplies stash', 'CJC-1295', 5, false, '2026-03-30'::date, '5', 'gift_giver', 'detailed', 'research_peptide_mock_reviews.json#id=5', '4b9681ad-22a1-51a8-8a14-02b14d6f2e66', 4, null),
  ('ec0e0000-0000-5000-8000-000000000006'::uuid, 'service'::public.testimonial_category, 'Dissolved cleanly, no clumping, and the box was packed better than I expected for the price.', 'FitMom42', 'Easy to work with', 'GHK-Cu', 5, true, '2026-07-01'::date, '6', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=6', '01a5445e-cf31-5049-8673-da32e06030f3', 5, null),
  ('ec0e0000-0000-5000-8000-000000000007'::uuid, 'fulfillment'::public.testimonial_category, 'Ordering was simple and I got a shipping notification within a few hours. The vial arrived in a padded box with an ice pack that was still cold on arrival. Reconstitution went smoothly with no visible residue. My only minor gripe is that the included instructions are pretty generic and could use more detail on storage temperature ranges, but a quick email to support cleared that up fast. Would order again.', 'Jennifer L.', 'Great experience start to finish', 'Epithalon', 5, true, '2026-05-08'::date, '7', 'verified_buyer', 'detailed', 'research_peptide_mock_reviews.json#id=7', '0a0d24c7-3e89-5bbe-89f0-58eb2d339ef0', 6, null),
  ('ec0e0000-0000-5000-8000-000000000008'::uuid, 'service'::public.testimonial_category, 'Fourth purchase, always shows up cold and on time. This is my go-to vendor now.', 'Chris P.', 'No complaints', 'NAD+', 5, true, '2026-06-25'::date, '8', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=8', 'f4db73ed-c1d1-5f5a-8e78-1e59d853a464', 7, null),
  ('ec0e0000-0000-5000-8000-000000000009'::uuid, 'documentation'::public.testimonial_category, 'I regularly cross-check vendors against my own lab''s testing equipment, and this most recent batch came in noticeably below the purity percentage listed on the certificate of analysis, roughly 4-5% lower by my measurement. Pros: fast shipping, good cold-chain packaging, and previous orders had matched their COAs closely. Cons: this inconsistency between batches is a real problem for anyone doing careful research, and support took three days to respond to my inquiry about the discrepancy, then mostly just offered a discount code rather than addressing the batch testing process. I''ll order again to see if this was a one-off, but I''m watching closely.', 'Dr. Alvarez (independent lab)', 'Purity lower than the listed COA on one batch', 'Thymosin Alpha-1', 3, true, '2026-04-11'::date, '9', 'technical_expert', 'detailed', 'research_peptide_mock_reviews.json#id=9', 'a0273600-ff44-5667-89e1-667cdb93c625', 8, null),
  ('ec0e0000-0000-5000-8000-000000000010'::uuid, 'fulfillment'::public.testimonial_category, 'Quick shipping, well packaged, no issues at all.', 'GymRat_87', 'Solid', 'Selank', 5, true, '2026-07-05'::date, '10', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=10', 'c08be340-d8e1-5329-8890-eaacd8efc803', 9, null),
  ('ec0e0000-0000-5000-8000-000000000011'::uuid, 'service'::public.testimonial_category, 'I''ve placed five orders over the last several months and every single one has arrived with the ice pack still frozen and the vial intact. The COA is included every time and the batch numbers are easy to look up on their site. Pricing is fair compared to similar vendors I''ve tried in the past, though not the cheapest option out there. Customer service answered a question about storage within a couple hours. Overall a dependable choice.', 'Nicole H.', 'Consistently good over multiple orders', 'Semax', 5, true, '2026-06-14'::date, '11', 'verified_buyer', 'detailed', 'research_peptide_mock_reviews.json#id=11', '302cfdbc-45dd-5247-8e81-78d8d4e5626d', 10, null),
  ('ec0e0000-0000-5000-8000-000000000012'::uuid, 'fulfillment'::public.testimonial_category, 'Packaging was a little plain but everything arrived intact and on schedule.', 'Katie J.', 'Pretty good overall', 'PT-141', 4, true, '2026-05-27'::date, '12', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=12', 'a41f304f-fd88-597e-816b-5a7b703fac74', 11, null),
  ('ec0e0000-0000-5000-8000-000000000013'::uuid, 'fulfillment'::public.testimonial_category, 'Straightforward checkout, tracking updated regularly, product arrived cold and sealed.', 'Kevin M.', 'Will reorder', 'AOD-9604', 5, true, '2026-06-30'::date, '13', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=13', 'eb80bbc7-9851-550c-8f44-438368ed15e2', 12, null),
  ('ec0e0000-0000-5000-8000-000000000014'::uuid, 'documentation'::public.testimonial_category, 'What sets this vendor apart for me is that every vial has a batch number that maps to a downloadable COA on their site, so I can archive the documentation alongside my notes without having to email anyone. Reconstitution was clean and dissolved fully within a minute of adding BAC water. The only con worth mentioning is that lead times can stretch during high-demand periods, so if you''re on a strict testing schedule it''s worth ordering a week or two ahead. Otherwise no complaints on the product itself.', 'BioHacker_Dave', 'Batch traceability is a nice touch', 'MOTS-c', 5, true, '2026-03-19'::date, '14', 'technical_expert', 'detailed', 'research_peptide_mock_reviews.json#id=14', 'cf1bd0f5-48c7-58c2-8564-18c19f41b188', 13, null),
  ('ec0e0000-0000-5000-8000-000000000015'::uuid, 'service'::public.testimonial_category, 'Ordered on a Monday, had it by Thursday, everything packed well.', 'Ryan V.', 'Fast and easy', 'Sermorelin', 5, true, '2026-07-10'::date, '15', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=15', '436ba05b-283f-5a96-8c1d-5e4fc89b0814', 14, null),
  ('ec0e0000-0000-5000-8000-000000000016'::uuid, 'documentation'::public.testimonial_category, 'She''s particular about vendors and gave this one her approval, said the vial and paperwork looked exactly right.', 'HubbyBuysGifts', 'Got this for my wife''s home lab setup', 'DSIP', 5, false, '2026-05-02'::date, '16', 'gift_giver', 'short', 'research_peptide_mock_reviews.json#id=16', '004cca62-dfda-5db9-831f-6c3638018793', 15, null),
  ('ec0e0000-0000-5000-8000-000000000017'::uuid, 'documentation'::public.testimonial_category, 'This is a newer addition to their catalog and I was a little hesitant to order, but it was handled the same as their more established products. The ice pack was still solid when it arrived and the vial was double-sealed in bubble wrap. Documentation included a COA with a lot number I could look up. My only small complaint is the price is a bit higher than some of their other peptides, which I assume is due to it being newer to the market. Would still recommend.', 'Stephanie Q.', 'Newer product line but well handled', 'Retatrutide', 5, true, '2026-06-08'::date, '17', 'verified_buyer', 'detailed', 'research_peptide_mock_reviews.json#id=17', '3a1b4a50-ed01-5e75-85d6-ff9c40b74d13', 16, null),
  ('ec0e0000-0000-5000-8000-000000000018'::uuid, 'documentation'::public.testimonial_category, 'The peptide itself checked out fine against the listed specs when I compared it to my own reference standards. Packaging and cold-chain handling were both solid, and the vial arrived with no signs of temperature excursion. My main criticism is with the website rather than the product: the batch lookup tool timed out twice before I could pull up the COA, and I ended up just emailing support for a PDF copy, which they sent promptly. Worth ordering, just be patient with the site.', 'ResearchNerd', 'Good product, minor site friction', 'Cagrilintide', 4, true, '2026-04-27'::date, '18', 'technical_expert', 'detailed', 'research_peptide_mock_reviews.json#id=18', '92bc6b29-7c74-57fa-87e5-4e4d524f2e74', 17, null),
  ('ec0e0000-0000-5000-8000-000000000019'::uuid, 'support'::public.testimonial_category, 'Tracking stalled after two days and support took over a week to even reply. Still waiting on a refund.', 'Justin C.', 'Order never showed up', 'Melanotan II', 1, true, '2026-04-03'::date, '19', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=19', '25d6ede3-3539-5ebe-8e5d-95f7d7b790e4', 18, null),
