  ('ec0e0000-0000-5000-8000-000000000021'::uuid, 'fulfillment'::public.testimonial_category, 'Everything arrived as described, cold pack still frozen, no complaints.', 'Derek N.', 'No issues', 'TB-500', 5, true, '2026-06-11'::date, '21', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=21', '97493c04-13b2-5d79-8a8c-6408c6b98b87', 20, null),
  ('ec0e0000-0000-5000-8000-000000000022'::uuid, 'service'::public.testimonial_category, 'I compared a few vendors before settling on this one and I''m glad I did. The COA was included in the box rather than just emailed, which I appreciated for record keeping. Shipping was two days faster than the estimate given at checkout. The only downside is that the site doesn''t offer a subscription or auto-reorder option, so I have to remember to place a new order manually each time. Small complaint for an otherwise excellent experience.', 'Amanda W.', 'Great vendor, would recommend to a colleague', 'Semaglutide', 5, true, '2026-05-19'::date, '22', 'verified_buyer', 'detailed', 'research_peptide_mock_reviews.json#id=22', '00bb24de-2c3c-51f1-8aee-acd21d6c4cb3', 21, null),
  ('ec0e0000-0000-5000-8000-000000000023'::uuid, 'service'::public.testimonial_category, 'Fair price and arrived quickly, box was a bit dented but the vial was fine.', 'Megan O.', 'Good value', 'Ipamorelin', 4, true, '2026-06-22'::date, '23', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=23', '391edeef-3860-5e68-86e1-7d2b6c5310c6', 22, null),
