  ('ec0e0000-0000-5000-8000-000000000025'::uuid, 'service'::public.testimonial_category, 'I''m not the one using this, my son asked for it specifically for some independent research he''s doing before grad school starts. I handled the ordering since it was a birthday gift and I wanted it to be a surprise. Checkout was simple, I got tracking updates the whole way, and it showed up two days before his birthday as planned. He confirmed the paperwork and packaging looked right once it arrived. Painless process from an outsider''s perspective.', 'GrandpaJoe', 'Ordered for my son who''s finishing his biochem degree', 'GHK-Cu', 5, false, '2026-03-25'::date, '25', 'gift_giver', 'detailed', 'research_peptide_mock_reviews.json#id=25', '80ab2c21-3d34-5a44-8be1-8955ece5b12e', 24, null),
  ('ec0e0000-0000-5000-8000-000000000026'::uuid, 'documentation'::public.testimonial_category, 'Ran a quick purity check against the COA and it matched closely. Good documentation practices from this vendor.', 'LabTechLisa', 'COA checks out', 'Epithalon', 5, true, '2026-06-17'::date, '26', 'technical_expert', 'short', 'research_peptide_mock_reviews.json#id=26', 'ee53ce13-947a-5aea-839e-4fd7884ef818', 25, null),
