  ('ec0e0000-0000-5000-8000-000000000028'::uuid, 'fulfillment'::public.testimonial_category, 'My first order got delayed due to a carrier issue that wasn''t really their fault, but customer support proactively emailed me an update and offered a small credit for the inconvenience. The product itself, once it arrived, was well packaged and included full documentation. I''ve ordered twice more since then without any hiccups. It says something when a company handles a shipping problem well rather than just ignoring it, so that experience actually earned my loyalty rather than losing it.', 'Rachel D.', 'Great after a rough first impression', 'Thymosin Alpha-1', 5, true, '2026-04-15'::date, '28', 'verified_buyer', 'detailed', 'research_peptide_mock_reviews.json#id=28', '16585305-62b2-51f6-8198-8c59ef0ee2c0', 27, null),
  ('ec0e0000-0000-5000-8000-000000000029'::uuid, 'service'::public.testimonial_category, 'Quality seems fine, just a bit more expensive than a couple other vendors I''ve compared it to.', 'Tom B.', 'Good but pricier than alternatives', 'Selank', 4, true, '2026-05-30'::date, '29', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=29', 'ee0b223d-e03f-56e6-8337-1171ae3216ec', 28, null),
