  ('ec0e0000-0000-5000-8000-000000000034'::uuid, 'service'::public.testimonial_category, 'Another smooth order with no delays, though I noticed the price crept up a little since my last purchase.', 'Paul I.', 'Good, just a bit pricier now', 'Sermorelin', 4, true, '2026-07-11'::date, '34', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=34', '1a1f4b75-9062-57e6-8729-cda149255bb0', 33, null),
  ('ec0e0000-0000-5000-8000-000000000035'::uuid, 'service'::public.testimonial_category, 'I''ve been a customer for about six months now and have placed close to ten orders across different products. Every single one has arrived properly packaged with an intact cold chain and matching documentation. Prices are competitive without feeling like a race to the bottom on quality, which is often a red flag with cheaper vendors. Customer service has been responsive on the couple occasions I needed to reach out. This has become my default vendor for anything I need in this category.', 'Christina U.', 'Consistently good over six months of ordering', 'DSIP', 5, true, '2026-04-08'::date, '35', 'verified_buyer', 'detailed', 'research_peptide_mock_reviews.json#id=35', '80e03327-827b-5dce-8cac-a033bdb64a64', 34, null),
