  ('ec0e0000-0000-5000-8000-000000000042'::uuid, 'fulfillment'::public.testimonial_category, 'Cold pack was still solid on arrival, just wish tracking updates came a little more frequently in transit.', 'Nicole H.', 'Good order overall', 'CJC-1295', 4, true, '2026-06-16'::date, '42', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=42', '95846f38-0f16-5e35-8898-83f4958772cf', 41, null),
  ('ec0e0000-0000-5000-8000-000000000043'::uuid, 'fulfillment'::public.testimonial_category, 'The vial and packaging were exactly what I expected based on the product photos, no complaints there. Shipping was quick and the cold pack was still cold when it arrived. My only real feedback is on the checkout process, it asked me to create an account with a fairly long password requirement which felt unnecessary for a one-time purchase. Not a huge deal, but worth mentioning since it added a couple extra minutes to what should be a quick process. Would still order again.', 'Katie J.', 'Good product, checkout could be smoother', 'GHK-Cu', 4, true, '2026-05-24'::date, '43', 'casual_user', 'detailed', 'research_peptide_mock_reviews.json#id=43', 'cd0bbaa3-1660-53a4-80c9-a98fbe848dfe', 42, null),
  ('ec0e0000-0000-5000-8000-000000000044'::uuid, 'fulfillment'::public.testimonial_category, 'Everything as expected, fast shipping and good packaging.', 'David R.', 'No complaints', 'Epithalon', 5, true, '2026-07-12'::date, '44', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=44', 'baaecac3-dbe1-54c2-8bba-a5a7fefa0bdc', 43, null),
  ('ec0e0000-0000-5000-8000-000000000045'::uuid, 'documentation'::public.testimonial_category, 'The COA included a testing date within a reasonable window of the ship date, which matters for anyone tracking degradation over time. Reconstitution was clean with the powder dissolving fully within thirty seconds, no visible clumping or residue on the vial walls. I compared the listed molecular weight and purity spec against what I typically see from other reputable vendors and everything lined up. The one thing I''d like to see improved is more detail on the recommended storage temperature range printed directly on the label rather than only in the online documentation.', 'ResearchNerd', 'Solid documentation and clean reconstitution', 'NAD+', 5, true, '2026-05-06'::date, '45', 'technical_expert', 'detailed', 'research_peptide_mock_reviews.json#id=45', 'db228340-17d2-5945-8cb5-1b443e58288f', 44, null),
  ('ec0e0000-0000-5000-8000-000000000046'::uuid, 'fulfillment'::public.testimonial_category, 'Arrived quickly and everything was packed securely.', 'FitMom42', 'Happy with this order', 'Thymosin Alpha-1', 5, true, '2026-06-29'::date, '46', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=46', 'af3ab7a7-ca7d-552e-814e-fd9b38f4b220', 45, null),
  ('ec0e0000-0000-5000-8000-000000000047'::uuid, 'fulfillment'::public.testimonial_category, 'Ordered multiple times now, always a consistent product, though the label has been a little smudged on the last two shipments.', 'Kevin M.', 'Reliable, minor packaging nitpick', 'Selank', 4, true, '2026-07-15'::date, '47', 'verified_buyer', 'short', 'research_peptide_mock_reviews.json#id=47', 'fea59efb-c508-538a-8683-a5ffc3d1c054', 46, null),
  ('ec0e0000-0000-5000-8000-000000000048'::uuid, 'fulfillment'::public.testimonial_category, 'Product was fine but shipping took longer than the estimate and the box was a little beat up.', 'Megan O.', 'Pretty good, shipping was slow', 'Semax', 4, true, '2026-04-30'::date, '48', 'casual_user', 'short', 'research_peptide_mock_reviews.json#id=48', '74766dac-8283-5fe1-8a87-1448f8c0b6f3', 47, null),
  ('ec0e0000-0000-5000-8000-000000000049'::uuid, 'service'::public.testimonial_category, 'Easy to order online and it arrived well before the date I needed it.', 'HubbyBuysGifts', 'Good gift option', 'PT-141', 5, false, '2026-03-21'::date, '49', 'gift_giver', 'short', 'research_peptide_mock_reviews.json#id=49', 'c7f3fa32-66c3-5e05-88b6-9766b91dfa1f', 48, null),
  ('ec0e0000-0000-5000-8000-000000000050'::uuid, 'service'::public.testimonial_category, 'I''ve been ordering from this site for almost a year and have never had a batch that felt off. Packaging is consistent, always arrives cold, and the COAs are easy to find on their site by batch number. Prices have stayed reasonable even as I''ve seen some competitors raise theirs. The only thing I''d change is adding more payment options at checkout, but that''s a minor gripe against an otherwise excellent track record. Highly recommend for anyone comparing vendors.', 'Brian S.', 'Great long-term vendor', 'AOD-9604', 5, true, '2026-05-11'::date, '50', 'verified_buyer', 'detailed', 'research_peptide_mock_reviews.json#id=50', '15c6d27f-0645-51f0-8e94-f6036c6b80a6', 49, null)
on conflict do nothing;

create or replace view public.published_testimonials
with (security_invoker = false) as
  select
    id,
    category,
    quote,
    display_name,
    approved_photo_url,
    alt_text,
    case when incentive_provided then incentive_disclosure else '' end as incentive_disclosure,
    relationship_to_business,
    sort_order,
    review_title,
    product_name,
    rating,
    verified_purchase,
    submission_date as review_date
  from public.testimonials
  where status = 'approved'
    and consent_verified = true
    and claim_review_passed = true
    and submission_date is not null
    and length(btrim(consent_record_reference)) > 0
    and length(btrim(source_record_reference)) > 0
    and length(btrim(verification_notes)) > 0
    and length(btrim(relationship_to_business)) > 0
    and reviewed_by is not null
    and reviewed_at is not null
    and length(btrim(quote)) > 0
    and length(btrim(display_name)) > 0
    and incentive_provided is not null
    and (incentive_provided = false or length(btrim(incentive_disclosure)) > 0)
    and published_at is not null;

grant select on public.published_testimonials to anon, authenticated;
